import 'dart:async';
import 'dart:convert';

import '../lib/event_parser.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

bool sameList(List<String> actual, List<String> expected) {
  if (actual.length != expected.length) return false;
  for (var index = 0; index < actual.length; index++) {
    if (actual[index] != expected[index]) return false;
  }
  return true;
}

Future<void> main() async {
  final encoded = utf8.encode('data: caf?\n');
  final marker = encoded.indexOf(0xc3);
  final split = Stream<List<int>>.fromIterable([
    encoded.sublist(0, marker + 1),
    encoded.sublist(marker + 1),
  ]);
  check(
    sameList(await parseEventData(split).toList(), ['caf?']),
    'split multibyte text is decoded without replacement characters',
  );

  final crlf = Stream<List<int>>.value(utf8.encode('data: accepted\r\n'));
  check(
    sameList(await parseEventData(crlf).toList(), ['accepted']),
    'proxy CRLF does not become event data',
  );
}
